import { writeOutput } from "./codegen";

const DOCS_URL = "https://v0.dev/docs/api/platform/quickstart";
const PLACEHOLDER_VALUE =
  "CoffeeSafeLocalCoffeeSafeLocalCoffeeSafeLocalCoffeeSaf";

function generateTypeScript(): string {
  const lines: string[] = [
    "// Auto-generated from v0 API docs.",
    `// Source: ${DOCS_URL}`,
    "// Regenerate: cd turbo && pnpm -F @vm0/firewalls-generator generate:v0",
    "//",
    "// DO NOT EDIT THIS FILE MANUALLY.",
    "",
    'import type { FirewallConfig } from "../contracts/firewalls";',
    "",
    "export const v0Firewall = {",
    '  name: "v0",',
    '  description: "v0 API",',
    "  placeholders: {",
    `    V0_TOKEN: "${PLACEHOLDER_VALUE}",`,
    "  },",
    "  apis: [",
    "    {",
    '      base: "https://api.v0.dev",',
    "      auth: {",
    "        headers: {",
    '          Authorization: "Bearer ${{ secrets.V0_TOKEN }}",',
    "        },",
    "      },",
    "      permissions: [],",
    "    },",
    "  ],",
    "} as const satisfies FirewallConfig;",
    "",
  ];
  return lines.join("\n");
}

export async function generate(): Promise<void> {
  console.error("Generating v0 firewall config...");
  const ts = generateTypeScript();
  writeOutput("v0", ts, import.meta.dirname);
}
